import React, { useEffect, useState } from "react";
import { fetchNotifications } from "../api";

export default function NotificationList() {
  const [data, setData] = useState([]);
  const [type, setType] = useState("");
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(false);

  const getColor = (type) => {
    if (type === "Placement") return "#22c55e";
    if (type === "Result") return "#3b82f6";
    if (type === "Event") return "#f59e0b";
    return "#888";
  };

  useEffect(() => {
    setLoading(true);

    fetchNotifications("", page, 20)
      .then((res) => {
        let notifications = res.notifications || res;

        // ✅ FILTER
        if (type) {
          notifications = notifications.filter((n) => n.Type === type);
        }

        // ✅ SORT (latest first)
        notifications.sort(
          (a, b) => new Date(b.Timestamp) - new Date(a.Timestamp)
        );

        setData(notifications);
      })
      .catch(() => setData([]))
      .finally(() => setLoading(false));
  }, [type, page]);

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "#0b0f17",
        color: "#fff",
        padding: "40px 20px",
      }}
    >
      <div style={{ maxWidth: "800px", margin: "auto" }}>
        {/* HEADER */}
        <h1
          style={{
            marginBottom: "20px",
            fontWeight: "600",
            letterSpacing: "0.5px",
          }}
        >
          Notifications
        </h1>

        {/* FILTER BUTTONS */}
        <div
          style={{
            marginBottom: "20px",
            display: "flex",
            gap: "10px",
            flexWrap: "wrap",
          }}
        >
          {["", "Event", "Result", "Placement"].map((t) => (
            <button
              key={t || "all"}
              onClick={() => {
                setType(t);
                setPage(1); // reset page when filter changes
              }}
              style={{
                padding: "8px 16px",
                borderRadius: "20px",
                border: "none",
                cursor: "pointer",
                background: type === t ? "#2563eb" : "#1f2937",
                color: "#fff",
                fontSize: "13px",
                transition: "all 0.2s ease",
              }}
            >
              {t || "All"}
            </button>
          ))}
        </div>

        {/* LIST */}
        <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
          {loading && (
            <p style={{ color: "#888" }}>Loading notifications...</p>
          )}

          {!loading && data.length === 0 && (
            <p style={{ color: "#888" }}>No notifications found</p>
          )}

          {!loading &&
            data.map((n) => (
              <div
                key={n.ID}
                style={{
                  background: "#1a1d23",
                  borderRadius: "12px",
                  padding: "16px",
                  borderLeft: `4px solid ${getColor(n.Type)}`,
                  transition: "all 0.2s ease",
                  cursor: "pointer",
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.transform = "scale(1.01)")
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.transform = "scale(1)")
                }
              >
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                  }}
                >
                  <span
                    style={{
                      fontSize: "12px",
                      color: getColor(n.Type),
                      fontWeight: "600",
                      textTransform: "uppercase",
                      letterSpacing: "0.5px",
                    }}
                  >
                    {n.Type}
                  </span>

                  <span style={{ fontSize: "12px", color: "#888" }}>
                    {new Date(n.Timestamp).toLocaleString()}
                  </span>
                </div>

                <p
                  style={{
                    marginTop: "8px",
                    lineHeight: "1.5",
                    fontSize: "15px",
                  }}
                >
                  {n.Message}
                </p>
              </div>
            ))}
        </div>

        {/* PAGINATION */}
        <div
          style={{
            marginTop: "25px",
            display: "flex",
            gap: "10px",
            justifyContent: "center",
          }}
        >
          <button
            onClick={() => setPage(page - 1)}
            disabled={page === 1}
            style={{
              padding: "8px 16px",
              background: "#1f2937",
              border: "none",
              color: "#fff",
              borderRadius: "6px",
              cursor: "pointer",
              opacity: page === 1 ? 0.5 : 1,
            }}
          >
            Prev
          </button>

          <span style={{ alignSelf: "center", color: "#888" }}>
            Page {page}
          </span>

          <button
            onClick={() => setPage(page + 1)}
            style={{
              padding: "8px 16px",
              background: "#2563eb",
              border: "none",
              color: "#fff",
              borderRadius: "6px",
              cursor: "pointer",
            }}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
